/// オンラインユーザー数ウィジェット
/// サーバーのオンラインユーザー数を表示します。
/// 30秒ごとに自動更新します。

@render() {
  let n = Mk:api("get-online-users-count", {}).count

  Ui:render([
    Ui:C:container({
      align: "center"
      children: [
        Ui:C:mfm({ text: "**オンラインユーザー**" })
        Ui:C:mfm({ text: `$[x4 **{n}**]` })
        Ui:C:mfm({ text: "<small>$[fg.color=888888 30秒ごとに更新]</small>" })
      ]
    })
  ])
}

render()
loop {
  Core:sleep(30000)
  render()
}
